let tab=document.getElementsByClassName('tab-btn'),tabDiv=document.getElementsByClassName('item-div');function removeClass(){for(var a=0;a<tab.length;a++)tab[a].classList.remove('active');for(a=0;a<tab.length;a++)tabDiv[a].classList.remove('show')}for(var i=0;i<tab.length;i++)tab[i].onclick=function(){removeClass();let a=this.getAttribute('data-target');if(document.getElementById(a).classList.add('show'),this.classList.add('active'),a=="discuss-post"){const a=document.createElement('script');a.src='/js/disqus.js',document.head.append(a)}}